async fn spawn_test_comms_drain(
    adapter: &Arc<MeerkatMachine>,
    session_id: &SessionId,
    mode: CommsDrainMode,
    comms_runtime: Arc<dyn CommsRuntime>,
    idle_timeout: Duration,
) {
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    let mut sessions = adapter.sessions.write().await;
    let entry = sessions
        .get_mut(&session_id)
        .expect("register_session must have created the entry");
    {
        let mut authority = entry
            .dsl_authority
            .lock()
            .unwrap_or_else(std::sync::PoisonError::into_inner);
        crate::meerkat_machine::dsl::MeerkatMachineMutator::apply(
            &mut *authority,
            crate::meerkat_machine::dsl::MeerkatMachineInput::AttachSessionIngress {
                comms_runtime_id: crate::meerkat_machine::dsl::CommsRuntimeId::from_runtime(
                    &comms_runtime,
                ),
            },
        )
        .expect("test drain peer-ingress authority should accept");
        crate::meerkat_machine::dsl::MeerkatMachineMutator::apply(
            &mut *authority,
            crate::meerkat_machine::dsl::MeerkatMachineInput::SpawnDrain {
                mode: crate::meerkat_machine::dsl::DrainMode::from(mode),
            },
        )
        .expect("test drain spawn authority should accept");
    }
    let handle = crate::comms_drain::spawn_comms_drain(
        Arc::clone(adapter),
        session_id.clone(),
        Arc::clone(&comms_runtime),
        Some(idle_timeout),
    );
    entry.drain_slot.install_task(comms_runtime, handle);
}

struct TestRotationCarrierDropSignal(Arc<AtomicBool>);

impl Drop for TestRotationCarrierDropSignal {
    fn drop(&mut self) {
        self.0.store(true, Ordering::SeqCst);
    }
}

async fn install_test_rotation_carrier(
    adapter: &Arc<MeerkatMachine>,
    session_id: &SessionId,
    runtime: Arc<dyn CommsRuntime>,
    operation_id: &str,
) -> Arc<AtomicBool> {
    let dropped = Arc::new(AtomicBool::new(false));
    let started = Arc::new(Notify::new());
    let carrier = tokio::spawn({
        let dropped = Arc::clone(&dropped);
        let started = Arc::clone(&started);
        async move {
            let _drop_signal = TestRotationCarrierDropSignal(dropped);
            started.notify_one();
            std::future::pending::<()>().await;
        }
    });
    started.notified().await;
    let rotation_slot = {
        let sessions = adapter.sessions.read().await;
        Arc::clone(
            &sessions
                .get(session_id)
                .expect("registered session entry")
                .supervisor_rotation_task,
        )
    };
    assert!(
        rotation_slot
            .install(operation_id.to_string(), runtime, carrier)
            .await,
        "test rotation carrier should install"
    );
    dropped
}

async fn current_phase(
    adapter: &Arc<MeerkatMachine>,
    session_id: &SessionId,
) -> Option<CommsDrainPhase> {
    let sessions = adapter.sessions.read().await;
    sessions.get(session_id).map(|entry| {
        let authority = entry
            .dsl_authority
            .lock()
            .unwrap_or_else(std::sync::PoisonError::into_inner);
        CommsDrainPhase::from(authority.state().drain_phase)
    })
}

async fn handle_present(adapter: &Arc<MeerkatMachine>, session_id: &SessionId) -> bool {
    let sessions = adapter.sessions.read().await;
    sessions
        .get(session_id)
        .is_some_and(|entry| entry.drain_slot.handle_present())
}

async fn wait_for_phase(
    adapter: &Arc<MeerkatMachine>,
    session_id: &SessionId,
    expected: CommsDrainPhase,
) {
    tokio::time::timeout(Duration::from_secs(1), async {
        loop {
            if current_phase(adapter, session_id).await == Some(expected) {
                break;
            }
            tokio::time::sleep(Duration::from_millis(5)).await;
        }
    })
    .await
    .expect("phase transition");
}

#[tokio::test]
async fn dismiss_exit_updates_authority_before_join() {
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    let comms_runtime: Arc<dyn CommsRuntime> = Arc::new(FakeDrainRuntime::dismissing());

    spawn_test_comms_drain(
        &adapter,
        &session_id,
        CommsDrainMode::PersistentHost,
        comms_runtime,
        Duration::from_millis(25),
    )
    .await;

    wait_for_phase(&adapter, &session_id, CommsDrainPhase::Stopped).await;
    assert!(
        !handle_present(&adapter, &session_id).await,
        "drain task should clear its slot before wait_comms_drain joins"
    );

    adapter
        .wait_comms_drain(&session_id)
        .await
        .expect("wait_comms_drain");
    assert_eq!(
        current_phase(&adapter, &session_id).await,
        Some(CommsDrainPhase::Stopped)
    );
}

