#[tokio::test]
async fn supervisor_rotation_persistence_failures_leave_cold_resumable_checkpoints() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let fault_store = Arc::new(RuntimeCommitAtomicityStore::pass_through(inner));
    let store: Arc<dyn RuntimeStore> = fault_store.clone();
    let session_id = SessionId::new();
    let previous_peer_id = meerkat_core::comms::PeerId::from_ed25519_pubkey(&[0xbb; 32]).as_str();
    let next_peer_id = meerkat_core::comms::PeerId::from_ed25519_pubkey(&[0xdd; 32]).as_str();
    let previous_signing_key = crate::comms_drain::encode_supervisor_signing_public_key([0xbb; 32]);
    let next_signing_key = crate::comms_drain::encode_supervisor_signing_public_key([0xdd; 32]);
    let operation_id = uuid::Uuid::new_v4().to_string();

    let mut machine = MeerkatMachine::persistent_without_blobs(Arc::clone(&store));
    machine
        .register_session(session_id.clone())
        .await
        .expect("register persistent supervisor rotation");
    let endpoint_runtime: Arc<dyn CommsRuntime> = Arc::new(RotationEndpointRuntime {
        notify: Arc::new(Notify::new()),
    });
    machine
        .stage_local_endpoint_for_comms_runtime(&session_id, endpoint_runtime.as_ref())
        .await
        .expect("stage rotation local endpoint");
    machine
        .stage_supervisor_bind(
            &session_id,
            "previous-supervisor".to_string(),
            previous_peer_id.clone(),
            "inproc://previous-supervisor".to_string(),
            previous_signing_key.clone(),
            1,
        )
        .await
        .expect("stage previous supervisor");
    machine
        .stage_supervisor_trust_published(&session_id, previous_peer_id.clone(), 1)
        .await
        .expect("persist previous supervisor binding");

    fault_store
        .fail_commit_machine_lifecycle
        .store(true, Ordering::SeqCst);
    assert!(matches!(
        machine
            .submit_supervisor_rotation(
                &session_id,
                GeneratedSupervisorRotationSubmit {
                    operation_id: operation_id.clone(),
                    next: GeneratedSupervisorBinding {
                        name: "next-supervisor".to_string(),
                        peer_id: next_peer_id.clone(),
                        address: "inproc://next-supervisor".to_string(),
                        signing_public_key: next_signing_key.clone(),
                        epoch: 2,
                    },
                    preflight_rejection: None,
                    sender_peer_id: Some(previous_peer_id.clone()),
                    sender_signing_public_key: Some(previous_signing_key.clone()),
                },
            )
            .await,
        Err(SupervisorBindingStageError::Persistence(_))
    ));
    assert!(matches!(
        machine.supervisor_binding(&session_id).await,
        SupervisorBinding::Bound { ref peer_id, epoch: 1, .. } if peer_id == &previous_peer_id
    ));

    machine
        .submit_supervisor_rotation(
            &session_id,
            GeneratedSupervisorRotationSubmit {
                operation_id: operation_id.clone(),
                next: GeneratedSupervisorBinding {
                    name: "next-supervisor".to_string(),
                    peer_id: next_peer_id.clone(),
                    address: "inproc://next-supervisor".to_string(),
                    signing_public_key: next_signing_key.clone(),
                    epoch: 2,
                },
                preflight_rejection: None,
                sender_peer_id: Some(previous_peer_id.clone()),
                sender_signing_public_key: Some(previous_signing_key.clone()),
            },
        )
        .await
        .expect("persist previous-revoke checkpoint");
    fault_store
        .fail_commit_machine_lifecycle
        .store(true, Ordering::SeqCst);
    assert!(matches!(
        machine
            .stage_supervisor_rotation_previous_revoked(
                &session_id,
                operation_id.clone(),
                previous_peer_id.clone(),
                1,
            )
            .await,
        Err(SupervisorBindingStageError::Persistence(_))
    ));
    drop(machine);

    machine = MeerkatMachine::persistent_without_blobs(Arc::clone(&store));
    machine
        .register_session(session_id.clone())
        .await
        .expect("recover previous-revoke checkpoint");
    assert_recovered_rotation_phase(
        &machine,
        &session_id,
        dsl::SupervisorRotationPhase::PreviousRevokePending,
    )
    .await;
    machine
        .stage_supervisor_rotation_previous_revoked(
            &session_id,
            operation_id.clone(),
            previous_peer_id.clone(),
            1,
        )
        .await
        .expect("persist next-publish checkpoint");
    fault_store
        .fail_commit_machine_lifecycle
        .store(true, Ordering::SeqCst);
    assert!(matches!(
        machine
            .stage_supervisor_rotation_next_published(
                &session_id,
                operation_id.clone(),
                next_peer_id.clone(),
                2,
            )
            .await,
        Err(SupervisorBindingStageError::Persistence(_))
    ));
    drop(machine);

    machine = MeerkatMachine::persistent_without_blobs(Arc::clone(&store));
    machine
        .register_session(session_id.clone())
        .await
        .expect("recover next-publish checkpoint");
    assert_recovered_rotation_phase(
        &machine,
        &session_id,
        dsl::SupervisorRotationPhase::NextPublishPending,
    )
    .await;
    machine
        .stage_supervisor_rotation_next_published(&session_id, operation_id, next_peer_id, 2)
        .await
        .expect("persist completed rotation receipt");
    drop(machine);

    let recovered = MeerkatMachine::persistent_without_blobs(store);
    recovered
        .register_session(session_id.clone())
        .await
        .expect("recover completed rotation receipt");
    assert_recovered_rotation_phase(
        &recovered,
        &session_id,
        dsl::SupervisorRotationPhase::Completed,
    )
    .await;
}

async fn persistent_staged_run_driver(
    store: Arc<dyn RuntimeStore>,
) -> (SharedDriver, LogicalRuntimeId, RunId, InputId) {
    // Direct driver tests do not go through MeerkatMachine's session
    // registration path, so use the UUID session alias as the contract-owned
    // session identity. Failed-but-applied validation intentionally rejects
    // opaque/non-session owner strings.
    let runtime_id = LogicalRuntimeId::legacy_session_uuid_alias(&SessionId::new());
    let mut driver = PersistentRuntimeDriver::new(runtime_id.clone(), store, memory_blob_store());
    let input = make_prompt("persistent terminalization");
    let input_id = input.id().clone();
    driver
        .accept_input(input)
        .await
        .expect("persistent input should be accepted");

    let run_id = RunId::new();
    driver
        .contract_begin_run_authority(run_id.clone())
        .expect("runtime run authority should begin through generated DSL");
    driver
        .machine_realize_authorized_stage_batch(
            crate::meerkat_machine::driver::test_authorized_stage_for_run(
                vec![input_id.clone()],
                run_id.clone(),
            ),
        )
        .expect("input should stage for the run");

    (
        Arc::new(Mutex::new(DriverEntry::Persistent(driver))),
        runtime_id,
        run_id,
        input_id,
    )
}

async fn mark_staged_runtime_turn_machine_failed(driver: &SharedDriver, run_id: &RunId) {
    use meerkat_core::turn_execution_authority::{
        ContentShape, TurnFailureSource, TurnFailureSourceKind, TurnPrimitiveKind,
    };

    let authority = driver.lock().await.shared_dsl_authority();
    let turn = crate::handles::RuntimeTurnStateHandle::new(Arc::new(
        crate::handles::HandleDslAuthority::from_shared(authority),
    ));
    turn.start_conversation_run(
        run_id.clone(),
        TurnPrimitiveKind::ConversationTurn,
        ContentShape::Conversation,
        false,
        false,
        0,
    )
    .expect("runtime turn should start");
    turn.primitive_applied(run_id.clone())
        .expect("runtime primitive should apply");
    turn.fatal_failure(
        run_id.clone(),
        TurnFailureSource::new(TurnFailureSourceKind::ToolError, "tool access denied"),
    )
    .expect("tool denial should terminalize through generated turn authority");
}

#[tokio::test]
async fn persistent_driver_recover_replaces_dead_process_phase_with_fresh_idle_shell() {
    let store = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let session_id = SessionId::new();
    let runtime_id = LogicalRuntimeId::for_session(&session_id);
    crate::store::RuntimeStore::commit_machine_lifecycle(
        store.as_ref(),
        &runtime_id,
        crate::store::MachineLifecycleCommit::new_with_binding(
            RuntimeState::Retired,
            crate::store::MachineLifecycleBindingFacts::default(),
            crate::store::SupervisorAuthoritySnapshot::UnboundNoReceipt,
        ),
        &[],
    )
    .await
    .expect("seed retired runtime state");

    let mut driver = PersistentRuntimeDriver::new(
        runtime_id.clone(),
        store.clone() as Arc<dyn RuntimeStore>,
        memory_blob_store(),
    );
    driver
        .recover()
        .await
        .expect("public persistent recover should use generated runtime authority");

    assert_eq!(driver.runtime_state(), RuntimeState::Idle);
    assert_eq!(
        crate::store::load_runtime_state(store.as_ref(), &runtime_id)
            .await
            .expect("load runtime state after recovery"),
        Some(RuntimeState::Idle),
        "cold recovery must normalize the dead process phase before rebuilding authority"
    );

    let authority = driver.inner_ref().shared_dsl_authority();
    let authority = authority
        .lock()
        .unwrap_or_else(std::sync::PoisonError::into_inner);
    assert_eq!(
        authority.state().lifecycle_phase,
        mm_dsl::MeerkatPhase::Idle
    );
}

fn assert_live_run_remains_staged(
    entry: &DriverEntry,
    run_id: &RunId,
    input_id: &InputId,
    context: &str,
) {
    assert_eq!(
        entry.runtime_state(),
        RuntimeState::Running,
        "{context}: runtime must remain running"
    );
    assert_eq!(
        entry.current_run_id(),
        Some(run_id.clone()),
        "{context}: active run id must remain bound"
    );
    assert_eq!(
        entry.input_phase(input_id),
        Some(crate::input_state::InputLifecycleState::Staged),
        "{context}: contributor must remain staged"
    );
    assert_eq!(
        entry.input_terminal_outcome(input_id),
        None,
        "{context}: contributor must not be consumed or otherwise terminal"
    );

    let authority = entry.shared_dsl_authority();
    let auth = authority
        .lock()
        .unwrap_or_else(std::sync::PoisonError::into_inner);
    assert_eq!(
        auth.state().lifecycle_phase,
        mm_dsl::MeerkatPhase::Running,
        "{context}: DSL lifecycle must remain Running"
    );
    assert_eq!(
        auth.state().current_run_id.as_ref().map(|id| id.0.as_str()),
        Some(run_id.to_string().as_str()),
        "{context}: DSL current_run_id must remain bound"
    );
    assert_eq!(
        auth.state().turn_phase,
        mm_dsl::TurnPhase::Ready,
        "{context}: DSL turn_phase must not become terminal"
    );
    assert_eq!(
        auth.state().terminal_outcome,
        None,
        "{context}: DSL terminal_outcome must not be set"
    );
    assert_eq!(
        auth.state().input_phases.get(&input_id.to_string()),
        Some(&mm_dsl::InputPhase::Staged),
        "{context}: DSL input phase must remain staged"
    );
}

async fn assert_commit_rejection_preserved_staged_batch(
    driver: &SharedDriver,
    run_id: &RunId,
    staged_ids: &[InputId],
) {
    let entry = driver.lock().await;
    assert_eq!(
        entry.runtime_state(),
        RuntimeState::Running,
        "rejected commit must preserve the active run"
    );
    assert_eq!(
        entry.current_run_id(),
        Some(run_id.clone()),
        "rejected commit must preserve the active run id"
    );
    for input_id in staged_ids {
        assert_eq!(
            entry.input_phase(input_id),
            Some(crate::input_state::InputLifecycleState::Staged),
            "rejected commit must leave every contributor staged"
        );
    }
}

